const express = require('express');
const app = express();
const projectsRouter = require('./modules/projects/routes').router;
const membersRouter = require('./modules/members/routes').router;
const tasksRouter = require('./modules/tasks/routes').router;
const commentsRouter = require('./modules/comments/routes').router;

app.use(express.json());

// Health check endpoint
app.get('/health', (req, res) => {
  res.json({ ok: true });
});

// Project routes
app.use('/projects', projectsRouter);
app.use('/projects/:projectId/members', membersRouter);
app.use('/projects/:projectId/tasks', tasksRouter);
app.use('/projects/:projectId/tasks/:taskId/comments', commentsRouter);

module.exports = app;

const express = require('express');
const router = express.Router();
const projectsService = require('./service').service;

router.post('/', (req, res) => {
  if (!req.body.name) return res.status(400).json({ error: { code: 'BAD_REQUEST', message: 'Name is required' } });
  const project = projectsService.createProject(req.body.name);
  res.status(201).json({ project });
});

module.exports = { router };

const express = require('express');
const router = express.Router();
const membersService = require('./service').service;

router.post('/', (req, res) => {
  if (!req.body.userId || !req.body.role) return res.status(400).json({ error: { code: 'BAD_REQUEST', message: 'UserId and role are required' } });
  const member = membersService.addMember(req.params.projectId, req.body);
  res.status(201).json({ member });
});

module.exports = { router };

const express = require('express');
const router = express.Router();
const tasksService = require('./service').service;

router.post('/', (req, res) => {
  const task = tasksService.createTask(req.params.projectId, { status: 'todo' });
  res.status(201).json({ task });
});

router.patch('/:taskId', (req, res) => {
  if (!['todo', 'done'].includes(req.body.status)) return res.status(400).json({ error: { code: 'BAD_REQUEST', message: 'Invalid status' } });
  const task = tasksService.updateTaskStatus(req.params.taskId, req.body.status);
  if (!task) return res.status(404).json({ error: { code: 'NOT_FOUND', message: 'Task not found' } });
  res.json({ task });
});

router.get('/', (req, res) => {
  const tasks = tasksService.getTasksByStatus(req.params.projectId, req.query.status);
  res.json({ tasks });
});

module.exports = { router };

const express = require('express');
const router = express.Router();
const commentsService = require('./service').service;

router.post('/', (req, res) => {
  if (!req.body.message) return res.status(400).json({ error: { code: 'BAD_REQUEST', message: 'Message is required' } });
  const comment = commentsService.addComment(req.params.taskId, req.body);
  res.status(201).json({ comment });
});

module.exports = { router };

class BadRequestError extends Error {
  constructor(message) {
    super(message);
    this.name = 'BadRequestError';
    this.code = 'BAD_REQUEST';
  }
}

class NotFoundError extends Error {
  constructor(message) {
    super(message);
    this.name = 'NotFoundError';
    this.code = 'NOT_FOUND';
  }
}

exports.sendError = (res, status, code, message) => {
  res.status(status).json({ error: { code, message } });
};

const app = require('./app');
const port = process.env.PORT || 3000;

module.exports = app;

const projects = {};
const { randomUUID } = require('node:crypto');

module.exports.addProject = (name) => {
  const id = randomUUID();
  projects[id] = { id, name };
  return { id, name };
};

module.exports.getProjectById = (projectId) => {
  return projects[projectId];
};
module.exports.createProject = module.exports.addProject;

const tasksStore = [];
export function getTasks() {
  return tasksStore;
}
export function createTask(name) {
  const task = { id: randomUUID(), name, status: 'todo' };
tasksStore.push(task);
return task;
}
export function updateTaskStatus(id, status) {
  const taskIndex = tasksStore.findIndex(task => task.id === id);
  if (taskIndex !== -1) {
    tasksStore[taskIndex].status = status;
  }
  return tasksStore.find(task => task.id === id);
}
module.exports = { getTasks, createTask, updateTaskStatus };

const membersStore = [];
export function getMembers() {
  return membersStore;
}
export function addMember(userId, role) {
  const member = { id: randomUUID(), userId, role };
  membersStore.push(member);
  return member;
}
module.exports = { getMembers, addMember };
const __botEvalMembersDupGuard = module.exports.addMember;
module.exports.addMember = async function addMember(projectId, userId, role) {
  const projectKey = String(projectId || '');
  const userKey = String(userId || '');
  const existing = typeof module.exports.getMembers === 'function' ? await module.exports.getMembers(projectKey) : [];
  if (Array.isArray(existing) && existing.some(member => member && String(member.userId || '') === userKey)) {
    return null;
  }
  if (typeof __botEvalMembersDupGuard === 'function') {
    return __botEvalMembersDupGuard(projectId, userId, role);
  }
  return null;
};

const { randomUUID } = require('crypto');
const addComment = (data) => {
  if (!data.message) return null;
  const comment = { id: randomUUID(), ...data };
  return comment;
};
module.exports = { addComment };
